"""
Model V4: Hybrid Residual Architecture
Main Stream (MLP) + Residual Stream (Lightweight GRU)

Architecture:
- Main Stream: MLP for immediate baseline prediction
- Residual Stream: Lightweight GRU for dynamic error correction
- Output: main + residual (with residual scaling/clipping)
"""

import torch
import torch.nn as nn


class HybridResidualModel(nn.Module):
    """
    V4: Hybrid Residual Architecture
    
    Main Stream: MLP (current frame only)
    Residual Stream: Lightweight GRU (recent N frames)
    Output: Y_hat = Y_main + Y_res (with residual constraints)
    
    Args:
        in_dim: Input dimension (12 for sin/cos only, or 18 with velocity)
        seq_len: Sequence length for residual stream (default: 10)
        main_hidden: Hidden dimension for main stream MLP (default: 128)
        res_hidden: Hidden dimension for residual GRU (default: 64, lightweight)
        out_dim: Output dimension (8 for raw1..raw8)
        dropout: Dropout rate (default: 0.1)
        res_scale: Residual scaling factor (default: 0.1, to keep residual small)
        res_clip: Residual clipping value (default: None, no clipping)
    """
    
    def __init__(
        self,
        in_dim: int = 12,
        seq_len: int = 10,
        main_hidden: int = 128,
        res_hidden: int = 64,
        out_dim: int = 8,
        dropout: float = 0.1,
        res_scale: float = 0.1,
        res_clip: float = None
    ):
        super().__init__()
        
        self.in_dim = in_dim
        self.seq_len = seq_len
        self.out_dim = out_dim
        self.res_scale = res_scale
        self.res_clip = res_clip
        
        # Main Stream: MLP for immediate baseline
        self.main_stream = nn.Sequential(
            nn.Linear(in_dim, main_hidden),
            nn.LayerNorm(main_hidden),
            nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(main_hidden, main_hidden),
            nn.LayerNorm(main_hidden),
            nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(main_hidden, out_dim)
        )
        
        # Residual Stream: Lightweight GRU for dynamic correction
        self.res_gru = nn.GRU(
            input_size=in_dim,
            hidden_size=res_hidden,
            num_layers=1,
            batch_first=True,
            dropout=dropout if 1 > 1 else 0
        )
        
        # Residual output projection
        self.res_proj = nn.Sequential(
            nn.Linear(res_hidden, res_hidden // 2),
            nn.LayerNorm(res_hidden // 2),
            nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(res_hidden // 2, out_dim),
            nn.Tanh()  # Constrain residual to [-1, 1] range
        )
        
        self._init_weights()
    
    def _init_weights(self):
        """Initialize weights."""
        for m in self.modules():
            if isinstance(m, nn.Linear):
                nn.init.xavier_uniform_(m.weight)
                if m.bias is not None:
                    nn.init.zeros_(m.bias)
            elif isinstance(m, nn.GRU):
                for name, param in m.named_parameters():
                    if 'weight_ih' in name:
                        nn.init.xavier_uniform_(param.data)
                    elif 'weight_hh' in name:
                        nn.init.orthogonal_(param.data)
                    elif 'bias' in name:
                        nn.init.zeros_(param.data)
    
    def forward(self, x_current: torch.Tensor, x_seq: torch.Tensor = None) -> torch.Tensor:
        """
        Forward pass.
        
        Args:
            x_current: (batch, in_dim) current frame input
            x_seq: (batch, seq_len, in_dim) sequence of recent frames for residual stream
                  If None, only main stream is used
        
        Returns:
            (batch, out_dim) output predictions
        """
        # Main stream: immediate baseline prediction
        y_main = self.main_stream(x_current)  # (batch, out_dim)
        
        # Residual stream: dynamic correction
        if x_seq is not None and self.seq_len > 0:
            # GRU forward
            gru_out, _ = self.res_gru(x_seq)  # (batch, seq_len, res_hidden)
            # Use last timestep
            gru_last = gru_out[:, -1, :]  # (batch, res_hidden)
            # Project to residual
            y_res_raw = self.res_proj(gru_last)  # (batch, out_dim), range [-1, 1]
            
            # Scale residual (keep it small)
            y_res = y_res_raw * self.res_scale
            
            # Optional clipping
            if self.res_clip is not None:
                y_res = torch.clamp(y_res, -self.res_clip, self.res_clip)
        else:
            y_res = torch.zeros_like(y_main)
        
        # Final output: main + residual
        y_hat = y_main + y_res
        
        return y_hat

